import { ActionIcon, Avatar, Badge, Button, Card, Container, Divider, Flex, Grid, Group, Image, Modal, Space, Stack, Text, Textarea, Title } from "@mantine/core";
import { ActionArgs, LoaderArgs, TypedDeferredData, defer, json, redirect } from "@remix-run/node";
import { Await, Form, Link, useLoaderData } from "@remix-run/react";
import { IconEdit } from "@tabler/icons-react";
import { IconTrash } from "@tabler/icons-react";
import { Suspense, useEffect, useState } from "react";
import { useSelector } from "react-redux";
import ConfigureBooking from "~/components/ConfigureBooking";
import Skeleton from "~/components/Skeleton";
import UserLogin from "~/components/UserLogin";
import Routes from "~/routes.data";
import { CartService } from "~/service/cart.service";
import { userCartCookie } from "~/session.server";
import { getUser } from "~/store/user.store";
import { CartActiveService, CartInput, CartItem, CartItemService } from "~/types";
import { DateFormatter } from "~/utils/date.transform";

export async function action({ request }: ActionArgs) {
    const cookieHeader = request.headers.get("Cookie");
    let data: CartInput[] = await userCartCookie.parse(cookieHeader);

    const form = await request.formData();
    const deleteId = form.get('delete')?.toString();
    if (deleteId) {
        data = data.filter(x => x.vendorServiceGroupId !== deleteId);
    }

    return redirect(Routes.get('Cart'), {
        headers: {
            "Set-Cookie": await userCartCookie.serialize(data),
        },
    });;
}

export async function loader({ request }: LoaderArgs) {
    const cookieHeader = request.headers.get("Cookie");
    const cookie: CartInput[] = await userCartCookie.parse(cookieHeader);

    return defer({
        cartInput: JSON.stringify(cookie),
        data: CartService.summary(cookie)
    });
}



const Cart = {
    Index: () => {
        const user = useSelector(getUser);
        const data = useLoaderData<typeof loader>();

        return <Container size={'xl'} >
            <Title order={3}>Checkout</Title>
            <Space h={'md'} />
            <Grid gutter={30} justify="space-between">
                <Grid.Col span={{ base: 12, md: 4, lg: 8 }}>
                    <Suspense fallback={<Skeleton />}>
                        <Await resolve={data.data}>
                            {response => <Cart.Preview cart={response} />}
                        </Await>
                    </Suspense>
                </Grid.Col>
                <Grid.Col span={{ base: 12, md: 3, lg: 3 }}>
                    <Suspense fallback={<Skeleton />}>
                        <Await resolve={data.data}>
                            {response => response?.length ?
                                <Stack gap={'md'}>
                                    <Cart.Summary data={response} />
                                    {user ? <Form method="post" action="/order/checkout">
                                        <input type="hidden" name="source" value="cart" />
                                        <input type="hidden" name="cart" value={data.cartInput} />
                                        <Button variant="filled" type="submit" fullWidth>Place order</Button></Form> : <UserLogin title="Login to continue" redirectUrl="/cart/checkout" />}
                                </Stack> : ''
                            }
                        </Await>
                    </Suspense>
                </Grid.Col>
            </Grid>
        </Container>
    },
    Preview: ({ cart }: { cart: CartItem[] }) => {
        const [editService, setEditService] = useState<{ id: string, services: CartActiveService[] }>();

        function openEdtServiceDialog(id: string, services: CartActiveService[]) {
            setEditService({ id, services });
        }

        return <Stack>
            {cart.map((data, i) => <Grid gutter={20} key={data.vendorServiceGroupId + i}>
                <Grid.Col span={{ base: 12, md: 5 }}>
                    <Card withBorder>
                        <Card.Section>
                            <Image
                                style={{ width: '100%', height: '100px', objectFit: 'cover' }}
                                src={data.coverImg || ''}
                            />
                        </Card.Section>
                        <Space h="sm" />
                        <Group justify="space-between">
                            <Group gap={'md'}>
                                <Avatar src={data.vendorImg} />
                                <Link to={`/profile/${data.vendorId}`}>{data.vendorName}</Link>
                            </Group>
                            <Badge size="xs">{data.vendorType}</Badge>
                        </Group>
                        <Space h="md" />
                        <Text size="sm" fw={500}>{data.name}</Text>
                        <Space h="sm" />
                        <Group>
                            <Text size="sm" fw={500}>{DateFormatter.short(data.date)}</Text> -
                            <Text size="sm" fw={500}>From {data.timeHour} to {data.timeHour + data.duration} ({data.duration} hours)</Text>
                        </Group>
                        <Space h="md" />
                        <Divider />
                        <Space h="sm" />

                        <Flex justify={'end'} gap={'xs'}>
                            <Form method="post">
                                <ActionIcon type="submit" name="delete" value={data.vendorServiceGroupId} variant="subtle" color="red" size="lg" aria-label="remove">
                                    <IconTrash style={{ width: '70%', height: '70%' }} stroke={1.5} />
                                </ActionIcon>
                            </Form>
                            <Link to={Routes.get('CartAddEdit', { venderServiceGroupId: data.vendorServiceGroupId }) + '?source=cart'} >
                                <Button leftSection={<IconEdit style={{ width: '70%', height: '70%' }} stroke={1.5} />} variant="subtle">
                                    Modify
                                </Button>
                            </Link>
                        </Flex>
                    </Card>
                </Grid.Col>
                <Grid.Col span={{ base: 12, md: 7 }}>
                    <Stack>
                        <Text size="sm" fw={500}>Personal Note:</Text>
                        <Textarea
                            placeholder="Write down your requirements here..."
                            autosize
                            minRows={4}
                            maxRows={6}
                        />
                    </Stack>
                </Grid.Col>
            </Grid>)}
            {!cart?.length && <div>Sorry, Your cart is empty.</div>}

            {editService?.id && <Cart.Edit serviceId={editService.id} services={editService.services} onClose={() => setEditService(undefined)} />}
        </Stack>
    },
    Edit: (params: { serviceId: string, services: CartActiveService[], onClose: Function }) => {
        return <Modal opened={true} w={'1000px'} onClose={() => params.onClose()}>
            <ConfigureBooking minHour={1} vendorServiceGroupId={params.serviceId} options={params.services} />
        </Modal>
    },
    Summary: ({ data }: { data: CartItem[] }) => {
        const [orderSummary, setOrderSummary] = useState<{ total: number, gst: number, tax: number, final: number }>();
        useEffect(() => {
            const gst = 3;
            const total = data.reduce<CartItemService[]>((arr, i) => arr.concat(i.services), []).reduce((sum, item) => sum + item.cost, 0);
            const tax = (gst * total) / 100;

            setOrderSummary({
                total,
                tax,
                gst,
                final: total + tax
            })
        }, []);

        return <div style={{ border: '1px solid #e1e1e1', padding: '10px' }}>
            <Title order={4}>Order Summary</Title>
            {data.map(group => <div key={group.vendorServiceGroupId}>
                <b>{group.name}</b>
                {group.services.map(service => <Grid key={service.id} gutter={20} justify={'space-between'}>
                    <Grid.Col span="content"><Text size="sm" fw={500}>{service.name}</Text></Grid.Col>
                    <Grid.Col span="content"><Text size="sm">{service.cost} INR</Text></Grid.Col>
                </Grid>
                )}
            </div>)}
            <Divider />
            <Grid gutter={20} justify={'space-between'}>
                <Grid.Col span="content"><Text size="sm" fw={500}>Total</Text></Grid.Col>
                <Grid.Col span="content"><Text size="sm" fw={500}>{orderSummary?.total} INR</Text></Grid.Col>
            </Grid>
        </div>
    }
}


export default Cart.Index;